import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  PieChart, Pie, Cell, ResponsiveContainer, LineChart, Line,
  AreaChart, Area
} from 'recharts';
import Loader from '../common/Loader';

interface FeedbackStats {
  total: number;
  averageRating: number;
  ratingCounts: Record<number, number>;
  wordRatingCounts: Record<string, number>;
  topicCounts: Record<string, number>;
  recentTrends?: Array<{ date: string; count: number; avgRating: number }>;
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d', '#ff6b6b', '#4ecdc4'];

const AdminDashboard: React.FC = () => {
  const [stats, setStats] = useState<FeedbackStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [timeRange, setTimeRange] = useState<'week' | 'month' | 'all'>('week');
  const [recentFeedbacks, setRecentFeedbacks] = useState<any[]>([]);

  useEffect(() => {
    fetchStats();
    fetchRecentFeedbacks();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await api.get('/api/feedback/stats');
      let data = response.data.data || response.data;
      
      // Calculate rating counts from actual feedback data if not provided
      if (!data.ratingCounts && recentFeedbacks.length > 0) {
        const ratingCounts: Record<number, number> = {};
        const wordRatingCounts: Record<string, number> = {};
        const topicCounts: Record<string, number> = {};
        
        recentFeedbacks.forEach(fb => {
          // Count ratings
          ratingCounts[fb.rating] = (ratingCounts[fb.rating] || 0) + 1;
          
          // Count word ratings
          const wordRating = fb.wordRating;
          if (wordRating) {
            wordRatingCounts[wordRating] = (wordRatingCounts[wordRating] || 0) + 1;
          }
          
          // Count topics
          if (fb.topics && Array.isArray(fb.topics)) {
            fb.topics.forEach((topic: string) => {
              topicCounts[topic] = (topicCounts[topic] || 0) + 1;
            });
          }
        });
        
        data = {
          ...data,
          ratingCounts,
          wordRatingCounts,
          topicCounts
        };
      }
      
      setStats(data);
    } catch (err) {
      console.error('Error fetching stats:', err);
      setError('Failed to load statistics');
    } finally {
      setLoading(false);
    }
  };

  const fetchRecentFeedbacks = async () => {
    try {
      const response = await api.get('/api/feedback');
      let data = response.data.data || response.data;
      if (Array.isArray(data)) {
        setRecentFeedbacks(data);
      }
    } catch (err) {
      console.error('Error fetching recent feedbacks:', err);
    }
  };

  const getRatingLabel = (rating: number): string => {
    const labels: Record<number, string> = {
      1: 'Very Poor',
      2: 'Poor',
      3: 'Average',
      4: 'Good',
      5: 'Excellent'
    };
    return labels[rating] || 'Unknown';
  };

  const getRatingColor = (rating: number): string => {
    if (rating <= 2) return '#dc3545';
    if (rating === 3) return '#ffc107';
    return '#28a745';
  };

  const prepareTrendData = () => {
    if (!recentFeedbacks.length) return [];
    
    const trends: Record<string, { count: number; totalRating: number }> = {};
    const now = new Date();
    const daysToShow = timeRange === 'week' ? 7 : timeRange === 'month' ? 30 : 90;
    
    recentFeedbacks.forEach(fb => {
      const date = new Date(fb.createdAt);
      const dateKey = date.toISOString().split('T')[0];
      
      if (!trends[dateKey]) {
        trends[dateKey] = { count: 0, totalRating: 0 };
      }
      trends[dateKey].count++;
      trends[dateKey].totalRating += fb.rating;
    });
    
    // Generate last N days
    const result = [];
    for (let i = daysToShow - 1; i >= 0; i--) {
      const date = new Date(now);
      date.setDate(date.getDate() - i);
      const dateKey = date.toISOString().split('T')[0];
      const data = trends[dateKey] || { count: 0, totalRating: 0 };
      
      result.push({
        date: dateKey,
        count: data.count,
        avgRating: data.count > 0 ? data.totalRating / data.count : 0
      });
    }
    
    return result;
  };

  if (loading) return <Loader fullScreen text="Loading dashboard..." />;
  if (error) return <div style={styles.error}>{error}</div>;
  if (!stats) return <div style={styles.error}>No data available</div>;

  const ratingData = Object.entries(stats.ratingCounts || {})
    .map(([rating, count]) => ({
      rating: Number(rating),
      ratingLabel: getRatingLabel(Number(rating)),
      count,
    }))
    .sort((a, b) => a.rating - b.rating);

  const wordRatingData = Object.entries(stats.wordRatingCounts || {})
    .map(([word, count]) => ({ word, count }))
    .sort((a, b) => b.count - a.count);

  const topicData = Object.entries(stats.topicCounts || {})
    .map(([topic, count]) => ({ topic, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 10);

  const mostCommonRating = Object.entries(stats.ratingCounts || {})
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';
  
  const mostCommonWordRating = Object.entries(stats.wordRatingCounts || {})
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';
  
  const mostCommonTopic = Object.entries(stats.topicCounts || {})
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';
  
  const trendData = prepareTrendData();
  const totalFeedbacks = stats.total || recentFeedbacks.length;
  const avgRating = stats.averageRating || 
    (recentFeedbacks.reduce((sum, fb) => sum + fb.rating, 0) / totalFeedbacks || 0);

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📈 Admin Dashboard</h1>
      <p style={styles.subtitle}>Real-time feedback analytics and insights</p>

      {/* Summary Cards */}
      <div style={styles.summaryGrid}>
        <div style={styles.card}>
          <div style={styles.cardIcon}>📊</div>
          <div style={styles.cardTitle}>Total Feedbacks</div>
          <div style={styles.cardValue}>{totalFeedbacks}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>⭐</div>
          <div style={styles.cardTitle}>Average Rating</div>
          <div style={styles.cardValue}>{avgRating.toFixed(1)} / 5</div>
          <div style={styles.cardSubValue}>
            {avgRating >= 4 ? 'Excellent' : avgRating >= 3 ? 'Good' : avgRating >= 2 ? 'Average' : 'Poor'}
          </div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>🏆</div>
          <div style={styles.cardTitle}>Most Common Rating</div>
          <div style={styles.cardValue}>{mostCommonRating} ⭐</div>
          <div style={styles.cardSubValue}>{getRatingLabel(Number(mostCommonRating))}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>💬</div>
          <div style={styles.cardTitle}>Most Common Word Rating</div>
          <div style={styles.cardValue}>{mostCommonWordRating}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>📚</div>
          <div style={styles.cardTitle}>Most Popular Topic</div>
          <div style={styles.cardValue}>{mostCommonTopic.substring(0, 30)}</div>
        </div>
        <div style={styles.card}>
          <div style={styles.cardIcon}>🎯</div>
          <div style={styles.cardTitle}>Unique Topics</div>
          <div style={styles.cardValue}>{Object.keys(stats.topicCounts || {}).length}</div>
        </div>
      </div>

      {/* Trend Chart with Time Range Selector */}
      {trendData.length > 0 && (
        <div style={styles.fullWidthChart}>
          <div style={styles.chartHeader}>
            <h3>Feedback Trends</h3>
            <div style={styles.timeRangeSelector}>
              <button 
                onClick={() => setTimeRange('week')} 
                style={{...styles.rangeBtn, ...(timeRange === 'week' ? styles.activeRange : {})}}
              >
                Week
              </button>
              <button 
                onClick={() => setTimeRange('month')} 
                style={{...styles.rangeBtn, ...(timeRange === 'month' ? styles.activeRange : {})}}
              >
                Month
              </button>
              <button 
                onClick={() => setTimeRange('all')} 
                style={{...styles.rangeBtn, ...(timeRange === 'all' ? styles.activeRange : {})}}
              >
                All
              </button>
            </div>
          </div>
          <ResponsiveContainer width="100%" height={300}>
            <AreaChart data={trendData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" />
              <YAxis yAxisId="left" />
              <YAxis yAxisId="right" orientation="right" />
              <Tooltip />
              <Legend />
              <Area yAxisId="left" type="monotone" dataKey="count" fill="#8884d8" stroke="#8884d8" name="Feedback Count" />
              <Area yAxisId="right" type="monotone" dataKey="avgRating" fill="#82ca9d" stroke="#82ca9d" name="Average Rating" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      )}

      <div style={styles.chartsGrid}>
        {/* Rating Distribution Chart */}
        <div style={styles.chartCard}>
          <h3>Rating Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={ratingData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="ratingLabel" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" fill="#8884d8" name="Number of Feedbacks">
                {ratingData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={getRatingColor(entry.rating)} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Word Rating Distribution Pie Chart */}
        <div style={styles.chartCard}>
          <h3>Word Rating Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={wordRatingData}
                dataKey="count"
                nameKey="word"
                cx="50%"
                cy="50%"
                outerRadius={100}
                label={({ word, percent }) => `${word}: ${(percent * 100).toFixed(0)}%`}
              >
                {wordRatingData.map((_, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Top Topics Chart */}
        <div style={styles.fullWidthChart}>
          <h3>Top Topics</h3>
          <ResponsiveContainer width="100%" height={400}>
            <BarChart data={topicData} layout="vertical" margin={{ left: 100 }}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" />
              <YAxis type="category" dataKey="topic" width={200} />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" fill="#82ca9d" name="Number of Mentions" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Rating Summary */}
      <div style={styles.fullWidthChart}>
        <h3>Rating Summary</h3>
        <div style={styles.ratingSummary}>
          {ratingData.map(item => (
            <div key={item.rating} style={styles.ratingBar}>
              <div style={styles.ratingLabel}>{item.rating} ⭐ - {item.ratingLabel}</div>
              <div style={styles.barContainer}>
                <div 
                  style={{
                    ...styles.barFill,
                    width: `${(item.count / totalFeedbacks) * 100}%`,
                    backgroundColor: getRatingColor(item.rating)
                  }}
                />
              </div>
              <div style={styles.ratingCount}>{item.count} ({((item.count / totalFeedbacks) * 100).toFixed(1)}%)</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

